import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

export default function Login() {
    const navigate = useNavigate();

    const [form, setForm] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = e =>
        setForm(p => ({ ...p, [e.target.name]: e.target.value }));

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!form.email || !form.password) {
            setError('Please enter your email and password.');
            return;
        }

        setLoading(true);
        setError('');

        // 🔥 DEMO LOGIN LOGIC (NO BACKEND REQUIRED)
        setTimeout(() => {
            if (
                form.email === "demo@unmute.app" &&
                form.password === "Demo@1234"
            ) {
                localStorage.setItem("token", "demo-token");
                localStorage.setItem("user", JSON.stringify({
                    name: "Demo User",
                    email: "demo@unmute.app",
                    level: "Confident Communicator",
                    xp: 1200
                }));

                navigate('/Dashboard');
            } else {
                setError("Login failed. Please use demo credentials.");
            }

            setLoading(false);
        }, 1000);
    };

    return (
        <div className="min-h-screen bg-dark-900 flex items-center justify-center px-4 relative overflow-hidden">

            <div className="w-full max-w-md relative z-10">
                {/* Logo */}
                <div className="flex flex-col items-center mb-8">
                    <h1 className="font-bold text-3xl text-white">UnMute</h1>
                    <p className="text-white/40 text-sm mt-1">Turn Your Voice On</p>
                </div>

                <div className="bg-gray-800 p-8 rounded-xl shadow-lg">
                    <h2 className="text-xl font-bold text-white mb-1">Welcome back</h2>
                    <p className="text-white/40 text-sm mb-6">
                        Sign in to continue practicing
                    </p>

                    {error && (
                        <div className="mb-4 px-4 py-3 rounded bg-red-500/20">
                            <p className="text-red-400 text-sm">{error}</p>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-white text-sm">Email address</label>
                            <input
                                name="email"
                                type="email"
                                className="w-full p-2 mt-1 rounded bg-gray-700 text-white"
                                value={form.email}
                                onChange={handleChange}
                                required
                            />
                        </div>

                        <div>
                            <label className="text-white text-sm">Password</label>
                            <input
                                name="password"
                                type="password"
                                className="w-full p-2 mt-1 rounded bg-gray-700 text-white"
                                value={form.password}
                                onChange={handleChange}
                                required
                            />
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full bg-blue-600 hover:bg-blue-700 text-white py-2 rounded mt-2"
                        >
                            {loading ? "Signing in..." : "Sign In"}
                        </button>
                    </form>

                    {/* Demo Credentials */}
                    <div className="mt-6 p-3 rounded bg-blue-500/10 border border-blue-500/20">
                        <p className="text-blue-400 text-xs font-medium mb-1">
                            🧪 Demo Credentials
                        </p>
                        <p className="text-white/50 text-xs">
                            Email: <span className="text-white">demo@unmute.app</span>
                        </p>
                        <p className="text-white/50 text-xs">
                            Password: <span className="text-white">Demo@1234</span>
                        </p>
                    </div>

                    <p className="text-center text-sm text-white/40 mt-6">
                        Don't have an account?{" "}
                        <Link
                            to="/register"
                            className="text-blue-400 hover:text-blue-300"
                        >
                            Sign up free
                        </Link>
                    </p>
                </div>
            </div>
        </div>
    );
}
